'use strict';

/**
 * Phase N2.3: write tree-view/lib/fs-via-main.js and retarget fs-plus requires.
 *
 * Disk ops go through atom.applicationDelegate (main IPC). Pure path helpers
 * stay on fs-plus (isReadmePath, isCaseInsensitive, extension checks).
 *
 * Idempotent. Called from patch-packages-remote-ipc.js.
 */

const fs = require('fs');
const path = require('path');

const SHIM_SOURCE = `'use strict';

// Generated by script/lib/write-tree-view-fs-shim.js — do not edit by hand.
// Disk I/O → atom.applicationDelegate (main-process IPC, absolute paths only).
// String/path helpers remain on fs-plus (no disk).

const pathFs = require('fs-plus');

function d() {
  if (typeof atom === 'undefined' || !atom.applicationDelegate) {
    throw new Error('tree-view fs-via-main: atom.applicationDelegate unavailable');
  }
  return atom.applicationDelegate;
}

function realpathOrSelf(p) {
  return d().realpathSync(p) || p;
}

module.exports = {
  existsSync(p) {
    return d().existsSync(p);
  },
  isFileSync(p) {
    return d().isFileSync(p);
  },
  isDirectorySync(p) {
    return d().isDirectorySync(p);
  },
  isSymbolicLinkSync(p) {
    return d().isSymbolicLinkSync(p);
  },
  realpathSync(p) {
    return realpathOrSelf(p);
  },
  realpath(p, cb) {
    try {
      const r = realpathOrSelf(p);
      process.nextTick(() => cb(null, r));
    } catch (error) {
      process.nextTick(() => cb(error));
    }
  },
  makeTreeSync(p) {
    return d().makeTreeSync(p);
  },
  writeFileSync(p, data, encoding) {
    return d().writeFileSync(p, data, encoding);
  },
  readFileSync(p, encoding) {
    return d().readFileSync(p, encoding);
  },
  copySync(src, dest) {
    return d().copySync(src, dest);
  },
  copy(src, dest, cb) {
    try {
      d().copySync(src, dest);
      if (typeof cb === 'function') process.nextTick(cb);
    } catch (error) {
      if (typeof cb === 'function') process.nextTick(() => cb(error));
      else throw error;
    }
  },
  moveSync(src, dest) {
    return d().moveSync(src, dest);
  },
  renameSync(src, dest) {
    return d().renameSync(src, dest);
  },
  readdirSync(p) {
    return d().readdirSync(p);
  },
  listSync(p) {
    return d().listSync(p);
  },
  rmdirSync(p) {
    return d().rmdirSync(p);
  },
  statSync(p) {
    return d().statSync(p);
  },
  lstatSyncNoException(p) {
    return d().lstatSyncNoException(p);
  },
  statSyncNoException(p) {
    return d().statSyncNoException(p);
  },
  // Pure helpers (no disk)
  isCaseInsensitive() {
    return pathFs.isCaseInsensitive();
  },
  isReadmePath(p) {
    return pathFs.isReadmePath(p);
  },
  isCompressedExtension(ext) {
    return pathFs.isCompressedExtension(ext);
  },
  isImageExtension(ext) {
    return pathFs.isImageExtension(ext);
  },
  isPdfExtension(ext) {
    return pathFs.isPdfExtension(ext);
  },
  isBinaryExtension(ext) {
    return pathFs.isBinaryExtension(ext);
  }
};
`;

module.exports = function writeTreeViewFsShim(repoRoot) {
  const libDir = path.join(repoRoot, 'node_modules', 'tree-view', 'lib');
  if (!fs.existsSync(libDir)) {
    console.log('skip missing: node_modules/tree-view/lib');
    return;
  }

  const shimPath = path.join(libDir, 'fs-via-main.js');
  const prev = fs.existsSync(shimPath) ? fs.readFileSync(shimPath, 'utf8') : '';
  if (prev !== SHIM_SOURCE) {
    fs.writeFileSync(shimPath, SHIM_SOURCE);
    console.log('wrote: node_modules/tree-view/lib/fs-via-main.js');
  } else {
    console.log('ok (already): node_modules/tree-view/lib/fs-via-main.js');
  }

  const files = fs.readdirSync(libDir).filter(name => {
    return (
      (name.endsWith('.js') || name.endsWith('.coffee')) &&
      name !== 'fs-via-main.js'
    );
  });

  for (const name of files) {
    const abs = path.join(libDir, name);
    let text = fs.readFileSync(abs, 'utf8');
    const before = text;

    // JS
    text = text.replace(
      /const fs = require\(['"]fs-plus['"]\)/g,
      "const fs = require('./fs-via-main')"
    );
    text = text.replace(
      /let fs = require\(['"]fs-plus['"]\)/g,
      "let fs = require('./fs-via-main')"
    );
    text = text.replace(
      /var fs = require\(['"]fs-plus['"]\)/g,
      "var fs = require('./fs-via-main')"
    );

    // Coffee
    text = text.replace(
      /^fs = require 'fs-plus'/m,
      "fs = require './fs-via-main'"
    );
    text = text.replace(
      /^fs = require "fs-plus"/m,
      'fs = require "./fs-via-main"'
    );

    if (text !== before) {
      fs.writeFileSync(abs, text);
      console.log(`patched fs-plus→fs-via-main: node_modules/tree-view/lib/${name}`);
    }
  }
};

if (require.main === module) {
  module.exports(process.argv[2] || path.join(__dirname, '..', '..'));
}
